script.text:
      &ScriptQueryData;
      /* <flatten type="Javascript"> */
function active$FormExpense(f) {f.add_onResponseComplete(on$FormExpense$ResponseComplete);&ActiveForm;}
function close$FormExpense(f) {try {f.remove_onResponseComplete(on$FormExpense$ResponseComplete)} catch (ex) {};&CloseForm;}
function on$FormExpense$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_phi');
      break;
    default:
      break;
  }
}
/* </flatten> */
      &TabChanged;
      &ScriptIrregular;
